import{_ as l,C as o,o as e,c as d,j as t,a as r,b as i,w as n,E as p,a4 as h,a5 as E}from"./chunks/framework.sOZL8giL.js";const P=JSON.parse('{"title":"从零构建","description":"","frontmatter":{},"headers":[],"relativePath":"06-Agent评估/04-从零构建.md","filePath":"06-Agent评估/04-从零构建.md","lastUpdated":1774181700000}'),b={name:"06-Agent评估/04-从零构建.md"};function A(B,a,u,m,c,f){const s=o("Mermaid");return e(),d("div",null,[a[1]||(a[1]=t("h1",{id:"从零构建",tabindex:"-1"},[r("从零构建 "),t("a",{class:"header-anchor",href:"#从零构建","aria-label":'Permalink to "从零构建"'},"​")],-1)),a[2]||(a[2]=t("blockquote",null,[t("p",null,[r("本章是 "),t("strong",null,"Hermes Engineering 系列"),r("第 6 模块的第 4 章。")])],-1)),a[3]||(a[3]=t("p",null,"怎么从零开始搭建评估体系？九步路线图 + 工具选型。",-1)),a[4]||(a[4]=t("hr",null,null,-1)),a[5]||(a[5]=t("h2",{id:"九步路线图",tabindex:"-1"},[r("九步路线图 "),t("a",{class:"header-anchor",href:"#九步路线图","aria-label":'Permalink to "九步路线图"'},"​")],-1)),(e(),i(h,null,{default:n(()=>[p(s,{id:"mermaid-15",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E5%AE%9A%E4%B9%89%E8%AF%84%E4%BC%B0%E7%9B%AE%E6%A0%87%5D%20--%3E%20B%5B%E6%94%B6%E9%9B%86%E8%AF%84%E4%BC%B0%E6%95%B0%E6%8D%AE%3Cbr%2F%3E%E6%88%90%E5%8A%9F%2B%E5%A4%B1%E8%B4%A5%E6%A1%88%E4%BE%8B%5D%0A%20%20%20%20B%20--%3E%20C%5B%E5%AE%9A%E4%B9%89%E8%AF%84%E5%88%86%E6%A0%87%E5%87%86%3Cbr%2F%3E%E5%AE%A2%E8%A7%82%E5%8F%AF%E8%A1%A1%E9%87%8F%5D%0A%20%20%20%20C%20--%3E%20D%5B%E6%9E%84%E5%BB%BA%E8%AF%84%E5%88%86%E5%99%A8%3Cbr%2F%3E%E4%BB%A3%E7%A0%81%2F%E6%A8%A1%E5%9E%8B%2F%E4%BA%BA%E7%B1%BB%5D%0A%20%20%20%20D%20--%3E%20E%5B%E5%BB%BA%E7%AB%8B%E5%9F%BA%E7%BA%BF%3Cbr%2F%3EPass%40k%20Pass%5Ek%5D%0A%20%20%20%20E%20--%3E%20F%5B%E8%BF%AD%E4%BB%A3%E6%94%B9%E8%BF%9B%3Cbr%2F%3E%E6%AF%8F%E6%AC%A1%E5%8F%AA%E6%94%B9%E4%B8%80%E4%B8%AA%E5%8F%98%E9%87%8F%5D%0A%20%20%20%20F%20--%3E%20G%5B%E6%8C%81%E7%BB%AD%E8%BF%90%E8%A1%8C%3Cbr%2F%3E%E9%9B%86%E6%88%90%E5%88%B0%20CI%2FCD%5D%0A%20%20%20%20G%20--%3E%20H%5B%E5%88%86%E6%9E%90%E6%8A%A5%E5%91%8A%3Cbr%2F%3E%E8%B6%8B%E5%8A%BF%E6%AF%94%E7%BB%9D%E5%AF%B9%E5%80%BC%E9%87%8D%E8%A6%81%5D%0A%20%20%20%20H%20--%3E%20I%5B%E6%89%A9%E5%B1%95%E8%A6%86%E7%9B%96%3Cbr%2F%3E%E6%96%B0%E5%8A%9F%E8%83%BD%E6%96%B0%E5%A4%B1%E8%B4%A5%E6%A8%A1%E5%BC%8F%5D%0A%20%20%20%20I%20--%3E%20F%0A%20%20%20%20style%20A%20fill%3A%234a9%0A%20%20%20%20style%20G%20fill%3A%238cf%0A%20%20%20%20style%20I%20fill%3A%23f96%0A"})]),fallback:n(()=>[...a[0]||(a[0]=[r(" Loading... ",-1)])]),_:1})),a[6]||(a[6]=E(`<blockquote><p>💡 <strong>图解：</strong> 评估不是一次性工作——建基线、迭代改、持续跑、再扩展——改进循环永不停止。</p></blockquote><h3 id="第一步-定义评估目标" tabindex="-1">第一步：定义评估目标 <a class="header-anchor" href="#第一步-定义评估目标" aria-label="Permalink to &quot;第一步：定义评估目标&quot;">​</a></h3><p>问自己：我要评估什么？是 Agent 的整体能力还是某个具体维度？</p><p>明确目标后再决定评估的深度和广度。不要试图一步到位覆盖所有维度——从最重要的开始。</p><h3 id="第二步-收集评估数据" tabindex="-1">第二步：收集评估数据 <a class="header-anchor" href="#第二步-收集评估数据" aria-label="Permalink to &quot;第二步：收集评估数据&quot;">​</a></h3><p>从生产环境收集真实的输入输出对。包括成功的和失败的案例。数据质量比数量更重要——100 个高质量用例胜过 1000 个低质量用例。</p><p>注意隐私：收集数据时需要脱敏处理。注意版权：确保你有权使用这些数据做评估。</p><h3 id="第三步-定义评分标准" tabindex="-1">第三步：定义评分标准 <a class="header-anchor" href="#第三步-定义评分标准" aria-label="Permalink to &quot;第三步：定义评分标准&quot;">​</a></h3><p>每个评估维度需要明确的评分标准。好的标准是客观可衡量的。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>差的标准：</span></span>
<span class="line"><span>- 回答质量好</span></span>
<span class="line"><span></span></span>
<span class="line"><span>好的标准：</span></span>
<span class="line"><span>- 回答包含正确的 API 调用格式</span></span>
<span class="line"><span>- 回答引用了至少 3 个来源</span></span>
<span class="line"><span>- 回答没有超过 500 字</span></span>
<span class="line"><span>- 回答包含代码示例</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="第四步-构建评分器" tabindex="-1">第四步：构建评分器 <a class="header-anchor" href="#第四步-构建评分器" aria-label="Permalink to &quot;第四步：构建评分器&quot;">​</a></h3><p>根据评分标准选择评分器类型：</p><table tabindex="0"><thead><tr><th>标准类型</th><th>评分器</th><th>示例</th></tr></thead><tbody><tr><td>格式/语法</td><td>代码</td><td>JSON 格式是否正确</td></tr><tr><td>功能正确</td><td>代码</td><td>测试是否通过</td></tr><tr><td>语义正确</td><td>模型</td><td>回答是否准确</td></tr><tr><td>质量/风格</td><td>模型</td><td>报告是否有洞察</td></tr></tbody></table><h3 id="第五步-建立基线" tabindex="-1">第五步：建立基线 <a class="header-anchor" href="#第五步-建立基线" aria-label="Permalink to &quot;第五步：建立基线&quot;">​</a></h3><p>运行评估建立基线分数。这是改进的起点。没有基线就无法衡量改进。</p><p>记录当前的 Pass@k、Pass^k、平均分、分布情况。</p><h3 id="第六步-迭代改进" tabindex="-1">第六步：迭代改进 <a class="header-anchor" href="#第六步-迭代改进" aria-label="Permalink to &quot;第六步：迭代改进&quot;">​</a></h3><p>根据评估结果改进 Agent——可能是 Prompt 调整、工具改进、架构优化。每次改进后重新评估，比较分数变化。</p><p>关键：每次只改一个变量。同时改多个无法知道哪个改动产生了效果。</p><h3 id="第七步-持续运行" tabindex="-1">第七步：持续运行 <a class="header-anchor" href="#第七步-持续运行" aria-label="Permalink to &quot;第七步：持续运行&quot;">​</a></h3><p>评估不是一次性工作。持续运行评估检测退化。每次代码变更、Prompt 更新、模型升级后都运行评估。</p><p>自动化：将评估集成到 CI/CD 流程。每次 PR 合并前自动运行评估。</p><h3 id="第八步-分析和报告" tabindex="-1">第八步：分析和报告 <a class="header-anchor" href="#第八步-分析和报告" aria-label="Permalink to &quot;第八步：分析和报告&quot;">​</a></h3><p>评估结果要可视化。趋势比绝对值更重要——分数是在上升还是下降？</p><p>建立评估仪表板：按维度展示分数、按时间展示趋势、按失败模式分类。</p><h3 id="第九步-扩展覆盖" tabindex="-1">第九步：扩展覆盖 <a class="header-anchor" href="#第九步-扩展覆盖" aria-label="Permalink to &quot;第九步：扩展覆盖&quot;">​</a></h3><p>随着 Agent 能力增长，评估范围也要扩展。新的功能需要新的评估用例。新的失败模式需要加入评估集。</p><p>保持评估数据集的活力——定期审查、更新、淘汰过时用例。</p><hr><h2 id="评估工具选型" tabindex="-1">评估工具选型 <a class="header-anchor" href="#评估工具选型" aria-label="Permalink to &quot;评估工具选型&quot;">​</a></h2><h3 id="harbor" tabindex="-1">Harbor <a class="header-anchor" href="#harbor" aria-label="Permalink to &quot;Harbor&quot;">​</a></h3><p>开源评估框架。支持自定义评分器、批量评估、结果可视化。适合有工程能力的团队自己搭建评估系统。</p><h3 id="promptfoo" tabindex="-1">Promptfoo <a class="header-anchor" href="#promptfoo" aria-label="Permalink to &quot;Promptfoo&quot;">​</a></h3><p>专注于 Prompt 评估。快速对比不同 Prompt 版本的效果。支持多种 LLM 后端。适合 Prompt 迭代优化。</p><h3 id="braintrust" tabindex="-1">Braintrust <a class="header-anchor" href="#braintrust" aria-label="Permalink to &quot;Braintrust&quot;">​</a></h3><p>商业化评估平台。提供评估管理、结果分析、版本对比等功能。适合需要开箱即用方案的团队。</p><h3 id="langsmith" tabindex="-1">LangSmith <a class="header-anchor" href="#langsmith" aria-label="Permalink to &quot;LangSmith&quot;">​</a></h3><p>LangChain 生态的评估工具。与 LangChain 深度集成。支持 Trace 分析和评估。适合使用 LangChain 的团队。</p><h3 id="选型建议" tabindex="-1">选型建议 <a class="header-anchor" href="#选型建议" aria-label="Permalink to &quot;选型建议&quot;">​</a></h3><table tabindex="0"><thead><tr><th>需求</th><th>推荐</th></tr></thead><tbody><tr><td>完全自主控制</td><td>Harbor</td></tr><tr><td>快速 Prompt 对比</td><td>Promptfoo</td></tr><tr><td>开箱即用</td><td>Braintrust</td></tr><tr><td>LangChain 生态</td><td>LangSmith</td></tr></tbody></table><p>大多数团队从 Promptfoo 开始——快速、简单、够用。需要更复杂的评估流程时再升级到 Harbor 或 Braintrust。</p><hr><h2 id="常见错误" tabindex="-1">常见错误 <a class="header-anchor" href="#常见错误" aria-label="Permalink to &quot;常见错误&quot;">​</a></h2><p><strong>评估数据集太小</strong>：10 个用例不能代表真实场景。至少需要 50-100 个有代表性的用例。</p><p><strong>只评估成功案例</strong>：失败案例同样重要——甚至更重要。知道 Agent 在哪里失败比知道它在哪里成功更有价值。</p><p><strong>评分标准太主观</strong>：&quot;回答质量好&quot;无法自动化评估。用客观可衡量的标准。</p><p><strong>评估后不行动</strong>：评估的目的是改进。如果评估发现问题但不修复，评估就是浪费。</p><p><strong>过度评估</strong>：不是所有输出都需要深度评估。80% 的评估用代码评分器自动化完成。</p><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>九步路线图：定义目标 → 收集数据 → 定义标准 → 构建评分器 → 建立基线 → 迭代改进 → 持续运行 → 分析报告 → 扩展覆盖</li><li>工具选型：Harbor（自主）、Promptfoo（快速对比）、Braintrust（开箱即用）、LangSmith（LangChain 生态）</li><li>常见错误：数据集太小、只评成功、标准主观、评估后不行动</li></ul><hr><p><strong>上一章</strong>: <a href="./03-四类评估与纵深防御.html">四类评估与纵深防御</a></p><hr><h2 id="模块总结" tabindex="-1">模块总结 <a class="header-anchor" href="#模块总结" aria-label="Permalink to &quot;模块总结&quot;">​</a></h2><p>Agent 评估系列全部完结，共 4 章：</p><table tabindex="0"><thead><tr><th>章节</th><th>主题</th><th>核心概念</th></tr></thead><tbody><tr><td>1</td><td>为什么需要评估</td><td>Pass@k / Pass^k、随机性衡量</td></tr><tr><td>2</td><td>评分器体系</td><td>代码/模型/人类三角闭环</td></tr><tr><td>3</td><td>四类评估与纵深防御</td><td>瑞士奶酪模型、四层防御</td></tr><tr><td>4</td><td>从零构建</td><td>九步路线图、工具选型</td></tr></tbody></table><hr><p><a href="/">← 返回首页</a> | <a href="/07-生产实践/">下一模块: 生产实践 →</a></p>`,59))])}const q=l(b,[["render",A]]);export{P as __pageData,q as default};
